const items = $input.all();
const results = [];

for (const item of items) {
  let classification;
  if (item.json.output && item.json.output.classification) {
    classification = item.json.output.classification;
  } else if (item.json.classification) {
    classification = item.json.classification;
  } else {
    results.push({json: {error: "Classification missing", data: item.json}});
    continue;
  }

  const tier = classification.tier;
  const engagement = classification.engagement_rate;
  const niche = classification.niche;
  const followers = classification.followers;
  const ecomNiches = ['fashion', 'beauty', 'fitness', 'home_lifestyle', 'pets', 'parenting', 'food'];

  let strategy = '';
  let reason = '';
  let perks = [];
  let action = '';

  if (['micro', 'mid', 'macro'].includes(tier)) {
    strategy = 'ambassador_program';
    reason = `${classification.tier_name}-tier (${followers.toLocaleString()} followers) qualifies for ambassador program`;
    perks = ['Exclusive codes', 'Monthly products', 'Commission', 'Featured placement', 'Early access'];
    action = 'Send ambassador invitation';
  }
  else if (tier === 'nano' && engagement >= 3) {
    strategy = 'surprise_rewards';
    reason = `Nano with ${engagement}% engagement deserves recognition`;
    perks = ['Gift package', 'Thank-you note', 'Early access', 'Personalized selection'];
    action = 'Send surprise gift';
  }
  else if (ecomNiches.includes(niche) && engagement >= 1) {
    strategy = 'niche_specific_perks';
    reason = `${classification.niche_name} creator aligned with brand`;
    const nicheMap = {
      fashion: ['Styling sessions', 'Lookbook features', 'Collection previews'],
      beauty: ['Product bundles', 'Tutorial collabs', 'Routine features'],
      fitness: ['Gear packages', 'Challenges', 'Community access'],
      home_lifestyle: ['Makeover features', 'DIY opportunities'],
      pets: ['Product lines', 'Rescue partnerships'],
      parenting: ['Family bundles', 'Community access'],
      food: ['Recipe collabs', 'Kitchen tools']
    };
    perks = nicheMap[niche] || ['Category benefits', 'Collaboration opportunities'];
    action = 'Send niche perk offer';
  }
  else {
    strategy = 'standard_outreach';
    reason = 'Standard customer engagement';
    perks = ['Newsletter', 'Promotions', 'Community', 'Loyalty points'];
    action = 'Add to nurture';
  }

  let name = classification.username.replace(/[^a-zA-Z]/g, '') || 'Creator';

  results.push({
    json: {
      classification,
      routing: {
        strategy,
        reason,
        recommended_perks: perks,
        next_action: action,
        requires_personalization: (strategy !== 'standard_outreach'),
        priority_level: ['macro', 'mid'].includes(tier) ? 'high' : tier === 'micro' ? 'medium' : 'standard'
      },
      profile_data: {
        customer_name: name,
        niche_subcategory: classification.niche_subcategory,
        content_themes: classification.content_themes,
        username: classification.username,
        engagement_rate: engagement,
        followers,
        bio: classification.audience_demographics || ''
      }
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const c = item.json.classification || {};
  const r = item.json.routing || {};
  const p = item.json.output?.personalization || item.json.personalization || null;

  const tier = (c.tier_name || c.tier || '').toLowerCase();
  const eng = Number(c.engagement_rate || 0);
  const fit = Number(c.brand_fit_score || 0);
  const val = Number(c.value_score || 0);

  let level = 'none';
  let actions = [];
  let ambTier = null;
  let out = 'no_activation';

  if (['macro', 'mid'].includes(tier) && eng >= 5 && fit >= 8 && val >= 70) {
    level = 'elite_ambassador';
    ambTier = 'Elite';
    out = 'elite';
    actions = ['Welcome package (24hr)', '1-on-1 call', '15% commission', 'Portal access', '$500/mo products', 'Content rights (paid)', 'Private channel'];
  } else if (['micro', 'mid'].includes(tier) && eng >= 4 && fit >= 7 && val >= 60) {
    level = 'core_ambassador';
    ambTier = 'Core';
    out = 'core';
    actions = ['Welcome email', '12% commission', 'Portal access', '$200/mo products', 'Content rights (credit)', 'Community group'];
  } else if (((tier === 'nano' && eng >= 5) || (tier === 'micro' && val >= 75)) && fit >= 7) {
    level = 'rising_star';
    ambTier = 'Rising Star';
    out = 'rising';
    actions = ['Welcome email', '10% referral', 'Quarterly samples', 'Virtual meetups'];
  } else if (r.strategy_type === 'ambassador') {
    level = 'standard_ambassador';
    ambTier = 'Standard';
    out = 'standard';
    actions = ['Welcome email', '8% referral', 'Resources', 'Public events'];
  } else {
    actions = ['Continue standard routing'];
  }

  results.push({
    json: {
      classification: c,
      personalization: p,
      activation: {
        level,
        ambassador_tier: ambTier,
        actions,
        routing_output: out
      },
      profile_data: item.json.profile_data || null
    }
  });
}

return results;

parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "CreatorClassification",
  "type": "object",
  "required": ["classification"],
  "properties": {
    "classification": {
      "type": "object",
      "required": ["primary_platform", "tier", "niche", "niche_subcategory", "value_score", "reasoning"],
      "properties": {
        "primary_platform": {
          "type": "string",
          "enum": ["instagram", "tiktok", "youtube", "twitter"],
          "description": "Platform with highest engagement or most relevant audience"
        },
        "tier": {
          "type": "string",
          "enum": ["nano", "micro", "mid", "macro"],
          "description": "Influencer tier based on follower count"
        },
        "tier_name": {
          "type": "string",
          "description": "Human-readable tier name"
        },
        "niche": {
          "type": "string",
          "enum": [
            "fashion",
            "beauty",
            "fitness",
            "food",
            "home_lifestyle",
            "tech",
            "parenting",
            "travel",
            "pets",
            "business",
            "entertainment",
            "education",
            "art_photography",
            "automotive",
            "sports",
            "gaming",
            "music",
            "general"
          ],
          "description": "Primary content niche"
        },
        "niche_name": {
          "type": "string",
          "description": "Human-readable niche name"
        },
        "niche_subcategory": {
          "type": "string",
          "description": "Specific subcategory within niche (e.g., 'sustainable fashion', 'vegan cooking', 'exotic pets')"
        },
        "followers": {
          "type": "integer",
          "description": "Total follower count from primary platform"
        },
        "engagement_rate": {
          "type": "number",
          "description": "Engagement rate percentage"
        },
        "username": {
          "type": "string",
          "description": "Creator's username on primary platform"
        },
        "profile_url": {
          "type": "string",
          "description": "URL to primary platform profile"
        },
        "value_score": {
          "type": "integer",
          "minimum": 0,
          "maximum": 100,
          "description": "Overall value score for partnership potential (0-100)"
        },
        "content_themes": {
          "type": "array",
          "items": {"type": "string"},
          "maxItems": 5,
          "description": "Key content themes or topics (max 5)"
        },
        "audience_demographics": {
          "type": "string",
          "description": "Likely audience demographics based on content"
        },
        "brand_fit_score": {
          "type": "integer",
          "minimum": 0,
          "maximum": 10,
          "description": "How well they fit for e-commerce brand partnerships (1-10)"
        },
        "reasoning": {
          "type": "string",
          "description": "Brief explanation of classification decisions"
        }
      }
    }
  }
}
